import{_ as c,o,c as d,ai as a}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"在线状态","description":"","frontmatter":{"read_when":["调试实例标签页","排查重复或过期的实例行","更改 Gateway 网关 WS 连接或系统事件信标"],"summary":"OpenSoul 在线状态条目如何生成、合并和显示","title":"在线状态","x-i18n":{"generated_at":"2026-02-03T07:46:37Z","model":"claude-opus-4-5","provider":"pi","source_hash":"c752c76a880878fed673d656db88beb5dbdeefff2491985127ad791521f97d00","source_path":"concepts/presence.md","workflow":15}},"headers":[],"relativePath":"zh-CN/concepts/presence.md","filePath":"zh-CN/concepts/presence.md","lastUpdated":1771906665000}'),t={name:"zh-CN/concepts/presence.md"};function n(i,e,s,l,r,h){return o(),d("div",null,[...e[0]||(e[0]=[a('<h1 id="在线状态" tabindex="-1"><a class="header-anchor" href="#在线状态">#</a> 在线状态</h1><p>OpenSoul&quot;在线状态&quot;是以下内容的轻量级、尽力而为的视图：</p><ul><li><strong>Gateway 网关</strong>本身，以及</li><li><strong>连接到 Gateway 网关的客户端</strong>（mac 应用、WebChat、CLI 等）</li></ul><p>在线状态主要用于渲染 macOS 应用的<strong>实例</strong>标签页，并为运维人员提供快速可见性。</p><h2 id="在线状态字段-显示的内容" tabindex="-1"><a class="header-anchor" href="#在线状态字段-显示的内容">#</a> 在线状态字段（显示的内容）</h2><p>在线状态条目是具有以下字段的结构化对象：</p><ul><li><code>instanceId</code>（可选但强烈推荐）：稳定的客户端身份（通常是 <code>connect.client.instanceId</code>）</li><li><code>host</code>：人类友好的主机名</li><li><code>ip</code>：尽力而为的 IP 地址</li><li><code>version</code>：客户端版本字符串</li><li><code>deviceFamily</code> / <code>modelIdentifier</code>：硬件提示</li><li><code>mode</code>：<code>ui</code>、<code>webchat</code>、<code>cli</code>、<code>backend</code>、<code>probe</code>、<code>test</code>、<code>node</code>，...</li><li><code>lastInputSeconds</code>：&quot;自上次用户输入以来的秒数&quot;（如果已知）</li><li><code>reason</code>：<code>self</code>、<code>connect</code>、<code>node-connected</code>、<code>periodic</code>，...</li><li><code>ts</code>：最后更新时间戳（自纪元以来的毫秒数）</li></ul><h2 id="生产者-在线状态来源" tabindex="-1"><a class="header-anchor" href="#生产者-在线状态来源">#</a> 生产者（在线状态来源）</h2><p>在线状态条目由多个来源生成并<strong>合并</strong>。</p><h3 id="_1-gateway-网关自身条目" tabindex="-1"><a class="header-anchor" href="#_1-gateway-网关自身条目">#</a> 1）Gateway 网关自身条目</h3><p>Gateway 网关始终在启动时植入一个&quot;self&quot;条目，这样即使在任何客户端连接之前，UI 也能显示 Gateway 网关主机。</p><h3 id="_2-websocket-连接" tabindex="-1"><a class="header-anchor" href="#_2-websocket-连接">#</a> 2）WebSocket 连接</h3><p>每个 WS 客户端都以 <code>connect</code> 请求开始。在成功握手后，Gateway 网关为该连接更新插入一个在线状态条目。</p><h4 id="为什么一次性-cli-命令不会显示" tabindex="-1"><a class="header-anchor" href="#为什么一次性-cli-命令不会显示">#</a> 为什么一次性 CLI 命令不会显示</h4><p>CLI 经常为短暂的一次性命令进行连接。为避免实例列表被刷屏，<code>client.mode === &quot;cli&quot;</code> <strong>不会</strong>被转换为在线状态条目。</p><h3 id="_3-system-event-信标" tabindex="-1"><a class="header-anchor" href="#_3-system-event-信标">#</a> 3）<code>system-event</code> 信标</h3><p>客户端可以通过 <code>system-event</code> 方法发送更丰富的周期性信标。mac 应用使用此方法报告主机名、IP 和 <code>lastInputSeconds</code>。</p><h3 id="_4-节点连接-role-node" tabindex="-1"><a class="header-anchor" href="#_4-节点连接-role-node">#</a> 4）节点连接（role: node）</h3><p>当节点通过 Gateway 网关 WebSocket 以 <code>role: node</code> 连接时，Gateway 网关为该节点更新插入一个在线状态条目（与其他 WS 客户端流程相同）。</p><h2 id="合并-去重规则-为什么-instanceid-很重要" tabindex="-1"><a class="header-anchor" href="#合并-去重规则-为什么-instanceid-很重要">#</a> 合并 + 去重规则（为什么 <code>instanceId</code> 很重要）</h2><p>在线状态条目存储在单个内存映射中：</p><ul><li>条目以<strong>在线状态键</strong>为索引。</li><li>最佳键是稳定的 <code>instanceId</code>（来自 <code>connect.client.instanceId</code>），它在重启后仍然有效。</li><li>键不区分大小写。</li></ul><p>如果客户端在没有稳定 <code>instanceId</code> 的情况下重新连接，它可能会显示为<strong>重复</strong>行。</p><h2 id="ttl-和有界大小" tabindex="-1"><a class="header-anchor" href="#ttl-和有界大小">#</a> TTL 和有界大小</h2><p>在线状态是有意设计为短暂的：</p><ul><li><strong>TTL：</strong> 超过 5 分钟的条目会被修剪</li><li><strong>最大条目数：</strong> 200（最旧的优先删除）</li></ul><p>这使列表保持新鲜并避免无限制的内存增长。</p><h2 id="远程-隧道注意事项-回环-ip" tabindex="-1"><a class="header-anchor" href="#远程-隧道注意事项-回环-ip">#</a> 远程/隧道注意事项（回环 IP）</h2><p>当客户端通过 SSH 隧道/本地端口转发连接时，Gateway 网关可能会看到远程地址为 <code>127.0.0.1</code>。为避免覆盖客户端报告的有效 IP，回环远程地址会被忽略。</p><h2 id="消费者" tabindex="-1"><a class="header-anchor" href="#消费者">#</a> 消费者</h2><h3 id="macos-实例标签页" tabindex="-1"><a class="header-anchor" href="#macos-实例标签页">#</a> macOS 实例标签页</h3><p>macOS 应用渲染 <code>system-presence</code> 的输出，并根据最后更新的时间应用一个小的状态指示器（活跃/空闲/过期）。</p><h2 id="调试技巧" tabindex="-1"><a class="header-anchor" href="#调试技巧">#</a> 调试技巧</h2><ul><li>要查看原始列表，对 Gateway 网关调用 <code>system-presence</code>。</li><li>如果你看到重复项： <ul><li>确认客户端在握手中发送稳定的 <code>client.instanceId</code></li><li>确认周期性信标使用相同的 <code>instanceId</code></li><li>检查连接派生的条目是否缺少 <code>instanceId</code>（这种情况下重复是预期的）</li></ul></li></ul>',34)])])}const _=c(t,[["render",n]]);export{u as __pageData,_ as default};
